function countDiffAndIncrease(msg, metadata) {

    var newMsg = {};
    for (var k in msg) {
        if (msg.hasOwnProperty(k)) {
            newMsg[k] = msg[k];
        }
    }

    for (var key in msg) {

        if (!msg.hasOwnProperty(key)) {
            continue;
        }

        if (metadata[key] === undefined) {
            continue;
        }

        if (msg[key] !== metadata[key]) {

            var counterKey =
                (key === "bt")
                    ? "countBt"
                    : "count" + key.charAt(0).toUpperCase() + key.slice(1);

            var oldValue = metadata[counterKey];

            if (oldValue === undefined || oldValue === null) {
                oldValue = 0;
            }

            oldValue = parseInt(oldValue, 10);
            if (isNaN(oldValue)) {
                oldValue = 0;
            }

            var newValue = oldValue + 1;

            metadata[counterKey] = newValue;
            newMsg[counterKey] = newValue;
        }
    }

    return newMsg;
}


msg = countDiffAndIncrease(msg,metadata)
return {msg: msg, metadata: metadata, msgType: msgType};

